156: // ReadOnlyStore is a storage implementation which only supports
157: // reading the various types of state configuring within Flipt
158: type ReadOnlyStore interface {
159: 	ReadOnlyNamespaceStore
160: 	ReadOnlyFlagStore
161: 	ReadOnlySegmentStore
162: 	ReadOnlyRuleStore
163: 	ReadOnlyRolloutStore
164: 	EvaluationStore
