				Value:        constraint.Value.String,
				Description:  constraint.Description.String,
				CreatedAt:    cCreatedAt.Timestamp,
				UpdatedAt:    cUpdatedAt.Timestamp,
			})
		}
	}

	if err := rows.Err(); err != nil {
		return err
	}

	return rows.Close()
}

